interface UseUncontrolledInput<T> {\r
  /** Value for controlled state */\r
  value?: T;\r
  /** Initial value for uncontrolled state */\r
  defaultValue?: T;\r
  /** Final value for uncontrolled state when value and defaultValue are not provided */\r
  finalValue?: T;\r
  /** Controlled state onChange handler */\r
  onChange?: (value: T, ...payload: any[]) => void;\r
