export function useUncontrolled<T>({ value, defaultValue, finalValue, onChange = () => {} }: UseUncontrolledInput<T>): [T, (value: T, ...payload: any[]) => void, boolean] {\r
  const [uncontrolledValue, setUncontrolledValue] = useState(defaultValue !== undefined ? defaultValue : finalValue);\r
\r
  const handleUncontrolledChange = (val: T, ...payload: any[]) => {\r
    setUncontrolledValue(val);\r
    onChange?.(val, ...payload);\r
  };\r
\r
  if (value !== undefined) {\r
    return [value as T, onChange, true];\r
  }\r
\r
  return [uncontrolledValue as T, handleUncontrolledChange, false];\r
